import { NextRequest, NextResponse } from 'next/server';
import  extractProductFromImage  from '@/ai/flows/extract-product-from-image-flow';

export async function POST(req: NextRequest) {
  try {
    const { base64Image } = await req.json();

    if (!base64Image) {
      return NextResponse.json({ error: 'Base64 image is required' }, { status: 400 });
    }

    const result = await extractProductFromImage({ base64Image, imageType: 'image/jpeg' });
    return NextResponse.json(result);
  } catch (error: any) {
    console.error('Error in extract-product-from-image API route:', error);
    return NextResponse.json({ error: error.message || 'An unknown error occurred' }, { status: 500 });
  }
}